UPDATE property_data SET screenshot_url = NULL, street_view_url = NULL, fetched_at = NULL WHERE fetched_at >= now() - interval '7 days' OR address IN (SELECT DISTINCT COALESCE(j.address, c.address) FROM jobs j LEFT JOIN customers c ON c.id = j.customer_id WHERE j.scheduled_date BETWEEN CURRENT_DATE AND CURRENT_DATE + interval '14 days' AND COALESCE(j.address, c.address) IS NOT NULL UNION SELECT DISTINCT COALESCE(e.address, c.address) FROM estimates e LEFT JOIN customers c ON c.id = e.customer_id WHERE e.scheduled_date BETWEEN CURRENT_DATE AND CURRENT_DATE + interval '14 days' AND COALESCE(e.address, c.address) IS NOT NULL);